sql:
SELECT MAX(price) AS HighestPrice
FROM trades
WHERE crypto_id = (SELECT crypto_id FROM cryptocurrencies WHERE name = 'Bitcoin');

SELECT AVG(trade_count) AS average_trades
FROM (
  SELECT COUNT(trade_id) AS trade_count
  FROM trades
  GROUP BY user_id
);

